// EventBus — a synchronous publish/subscribe event bus
export type EventHandler<T = unknown> = (data: T) => void

export class EventBus {
  private readonly subs = new Map<string, Map<symbol, EventHandler>>()
  private readonly tokenIndex = new Map<symbol, string>()

  /**
   * Subscribe to an event. Returns an opaque token for unsubscription.
   * Use '*' as the event name to receive every emitted event.
   */
  subscribe<T = unknown>(event: string, handler: EventHandler<T>): symbol {
    if (!this.subs.has(event)) this.subs.set(event, new Map())
    const token = Symbol(event)
    this.subs.get(event)!.set(token, handler as EventHandler)
    this.tokenIndex.set(token, event)
    return token
  }

  /**
   * Unsubscribe using a token returned by subscribe().
   * Returns true if the token was found and removed, false otherwise.
   */
  unsubscribe(token: symbol): boolean {
    const event = this.tokenIndex.get(token)
    if (event === undefined) return false

    this.tokenIndex.delete(token)
    const handlers = this.subs.get(event)
    if (!handlers) return false

    const removed = handlers.delete(token)
    if (handlers.size === 0) this.subs.delete(event)
    return removed
  }

  /**
   * Emit an event, calling all subscribed handlers with the given data.
   * Wildcard ('*') subscribers are also notified for every event.
   */
  emit(event: string, data?: unknown): void {
    // Notify specific subscribers
    const handlers = this.subs.get(event)
    if (handlers) {
      for (const handler of handlers.values()) {
        handler(data)
      }
    }

    // Notify wildcard subscribers (skip if the emitted event IS '*' to avoid double-firing)
    if (event !== '*') {
      const wildcardHandlers = this.subs.get('*')
      if (wildcardHandlers) {
        for (const handler of wildcardHandlers.values()) {
          handler(data)
        }
      }
    }
  }

  /**
   * Subscribe for exactly one emission of an event, then auto-unsubscribe.
   * Returns a token that can be passed to unsubscribe() to cancel early.
   */
  once<T = unknown>(event: string, handler: EventHandler<T>): symbol {
    const wrapper: EventHandler<T> = (data: T) => {
      this.unsubscribe(token)
      handler(data)
    }
    const token = this.subscribe<T>(event, wrapper)
    return token
  }
}
```

### Key decisions

| Decision | Rationale |
|---|---|
| Wildcard check lives in `emit` | No changes to `subscribe`/`unsubscribe`; wildcard tokens are stored and removed exactly like normal tokens. |
| `event !== '*'` guard | Prevents wildcard handlers from firing twice if someone explicitly `emit('*', …)`. |
| Wildcard handlers receive only `data` | The handler signature `EventHandler<T>` carries data, not the event name. If callers need the originating event name, the data payload is the right place for it — changing the signature would be a breaking change. |
| `once` unsubscribes before calling handler | Prevents re-entrant emissions from triggering the handler a second time. |

